s=e.ib("\ud83c\udfb4 Getting Started","New to the app? Start here!",A.a(["1. Create a new deck or import an existing one","2. Add flashcards with questions and answers","3. Choose a study mode or game to practice","4. Track your progress and improve your learning"],b))
r=e.ib("\ud83c\udfe0 Home Screen Navigation","How to use the main interface",A.a(["**Deck Management:**","\u2022 Click on any deck title to edit it (blue, underlined)","\u2022 Use action icons below each deck:","  - \ud83d\uddd1\ufe0f Delete deck","  - \ud83d\udcc1 Move deck to another category","  - \ud83d\udccb Copy deck to another category","","**Top Bar Controls:**","\u2022 \ud83d\udd04 Refresh: Reload decks from storage","\u2022 \u21ba Reset: Reload default decks from assets","\u2022 \u2753 Help: Open this guide","\u2022 \ud83d\udd0a/\ud83d\udd07 Toggle sounds on/off","","**Categories:**","\u2022 Use dropdown to filter decks by category","\u2022 Default category contains built-in decks","\u2022 Create custom categories to organize your decks"],b))
q=e.ib("\ud83d\udcda Study Mode","Traditional flashcard review with audio",A.a(['\u2022 Click "Study" on any deck to start',"\u2022 Use arrow buttons to navigate between cards","\u2022 Tap the speaker icon to hear pronunciation","\u2022 Switch between front and back sides","\u2022 Enable shuffle for random review","\u2022 Try spaced retention for optimized learning"],b))
p=e.ib("\ud83c\udfae Game Modes","Make learning fun with games!",A.a(["**Typing Game**: Type answers from visual prompts","\u2022 Select question and answer sides","\u2022 Type your answer and submit","\u2022 Get instant feedback and scoring","","**Audio Typing Game**: Listen and type what you hear","\u2022 Click speaker to play audio","\u2022 Type the word or phrase you hear","\u2022 Use hints if you get stuck","","**Multiple Choice**: Select correct answers","\u2022 Choose from 4 possible answers","\u2022 Build speed and accuracy","","**Match Game**: Match corresponding cards","\u2022 Find pairs of matching content","\u2022 Test your memory and recognition","\u2022 \ud83d\udd0d Zoom controls: Adjust text size for better readability","\u2022 \ud83d\udcf1 Responsive layout: More cards on larger screens"],b))
o=e.ib("\ud83d\udd0a Audio Features","Enhanced text-to-speech for better learning",A.a(["\u2022 Automatic language detection","\u2022 High-quality voice synthesis","\u2022 Support for 9+ languages","\u2022 Natural speech rate (0.90)","\u2022 Click language button to change TTS language","","**Supported Languages:**","\u2022 English (en-US)","\u2022 Chinese (zh-CN)","\u2022 Japanese (ja-JP)","\u2022 Korean (ko-KR)","\u2022 Arabic (ar-SA)","\u2022 Russian (ru-RU)","\u2022 Thai (th-TH)","\u2022 Hindi (hi-IN)","\u2022 Hebrew (he-IL)"],b))
n=e.ib("\ud83d\udcc1 Import & Export","Share and backup your flashcards",A.a(["**Import Decks:**",'\u2022 Click "Import Deck" (green + button) on home screen',"\u2022 Upload a CSV file with deck data","\u2022 CSV Format: First row contains headers, subsequent rows contain data",'\u2022 Example: "Question,Answer\\nWhat is 2+2?,4\\nCapital of France?,Paris"',"","**Export Decks:**",'\u2022 Click "Export" on any deck (download icon)',"\u2022 Choose from multiple export options:","  - \ud83d\udce5 Download CSV file for spreadsheet editing","  - \ud83d\udce4 Share CSV file via email/messaging","  - \ud83d\udccb Copy CSV content to clipboard","","**Default Decks:**","\u2022 Built-in decks include Chinese Radicals, Hiragana, and more","\u2022 Click \u21ba (Reset) button to reload default decks from assets","\u2022 Useful if you updated asset files and want to see changes"],b))
m=e.ib("\u2699\ufe0f Settings & Customization","Personalize your learning experience",A.a(["\u2022 Compact mode for smaller screens","\u2022 Theme selection (light/dark)","### Audio Settings","- Click the **Help button** (\u2753) in the top-right for comprehensive guides","- **Language button**: In Study Mode, look for [\ud83e\udd16] button in the top bar","- **\ud83e\udd16 Auto-detect mode**: Automatically switches voices based on content language","- Chinese text \u2192 Chinese voice","- English text \u2192 English voice","- Best for mixed-language decks","- **Manual language selection**: Choose a specific language for all content","- All text uses the selected voice","- Consistent pronunciation practice","- **Override auto-detection**: Manual selection overrides automatic detection","- **Sound Effects**: Games now include audio feedback","- \ud83c\udfb5 Game start sound when any game begins","- \ud83c\udfaf Correct answer sound for right responses","- \u274c Error sound for wrong answers","- \ud83c\udfc1 Game over sound when completed","- \ud83d\udd07 **Mute/Unmute**: Click speaker icon in any game or home screen to toggle sounds","- Enhanced TTS provides natural pronunciation","- Adjustable speech rate in `lib/services/enhanced_tts_service.dart`","\u2022 Change speech rate: setSpeechRate(0.90)","\u2022 Modify voice selection in _setOptimalVoices()"],b))
l=e.ib("\ud83c\udfaf Learning Tips","Get the most out of your study sessions",A.a(["\u2022 Start with study mode to familiarize content","\u2022 Use games to test your knowledge","\u2022 Enable spaced retention for long-term memory","\u2022 Practice with audio for pronunciation","\u2022 Mix different game modes for variety","\u2022 Review difficult cards more frequently","\u2022 Import decks from others for new content"],b))
k=e.ib("\ud83d\udd27 Troubleshooting","Common issues and solutions",A.a(["**Audio not working?**","\u2022 Check browser permissions for audio","\u2022 Try refreshing the page","\u2022 Ensure speakers/headphones are connected","\u2022 Click \ud83d\udd0a/\ud83d\udd07 icon to toggle sounds on/off","","**New decks not appearing?**","\u2022 Click \ud83d\udd04 Refresh button to reload from storage","\u2022 Check if deck is in the correct category",'\u2022 Try switching to "All" category to see all decks',"","**Default decks outdated?**","\u2022 Click \u21ba Reset button to reload from asset files","\u2022 This updates default decks if you modified CSV files","\u2022 Your custom decks will be preserved","","**Game not starting?**","\u2022 Make sure deck has cards","\u2022 Check question/answer side selection","\u2022 Try different game modes","","**Match Game text too small?**","\u2022 Use \ud83d\udd0d Zoom In button to increase text size","\u2022 Use \ud83d\udd0d Zoom Out button to decrease text size","\u2022 Use \ud83d\udd0d Reset Zoom to return to normal size","","**Import not working?**","\u2022 Verify CSV format is correct (headers in first row)","\u2022 Check file size (should be < 5MB)","\u2022 Ensure required fields are present","\u2022 Try exporting a deck to see correct format"],b))
j=e.ib("\ud83d\udcf1 Keyboard Shortcuts","Navigate faster with shortcuts",A.a(["\u2022 **Space**: Play audio (when available)","\u2022 **Enter**: Submit answer (in games)","\u2022 **Arrow Keys**: Navigate cards (study mode)","\u2022 **Tab**: Move between input fields","\u2022 **Escape**: Close dialogs/menus"],b))
i=e.ib("\ud83d\udca1 Pro Tips","Advanced features for power users",A.a(["\u2022 Create decks with 3+ sides for complex content","\u2022 Use spaced retention for exam preparation","\u2022 Mix languages in same deck for bilingual practice","\u2022 Export progress data to track improvement","\u2022 Share decks with study groups","\u2022 Use audio typing for pronunciation practice","\u2022 Combine multiple games for comprehensive review"],b))
b=e.ib("\ud83c\udf10 Web vs Mobile","Platform-specific features",A.a(["**Web Version:**","\u2022 Full feature support","\u2022 Keyboard shortcuts available","\u2022 Easy sharing via URL","\u2022 No installation required","","**Mobile Version:**","\u2022 Touch-optimized interface","\u2022 On-the-go learning","\u2022 Offline capability","\u2022 Native app experience"],b))
